                MyClass myObject = (MyClass) obj;

                // Use the deserialized object safely
                myObject.someMethod();
            } else {
                System.out.println("Deserialized object is not of expected type.");
            }

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }

    private static class MyClass implements Serializable {
        public void someMethod() {
            System.out.println("Executing some method...");
        }
    }
}
